import{_ as e,o as a,c as r,a7 as o}from"./chunks/framework.C4ZIv4ii.js";const u=JSON.parse('{"title":"E-commerce Overview","description":"","frontmatter":{},"headers":[],"relativePath":"ecommerce/overview.md","filePath":"ecommerce/overview.md","lastUpdated":1781554731000}'),i={name:"ecommerce/overview.md"};function s(l,t,n,d,c,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="e-commerce-overview" tabindex="-1">E-commerce Overview <a class="header-anchor" href="#e-commerce-overview" aria-label="Permalink to &quot;E-commerce Overview&quot;">​</a></h1><p>Falcon CMS includes a complete e-commerce system built directly into the package — no extra plugins needed.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>Products</strong> with images, pricing, inventory, SKU</li><li><strong>Variable products</strong> — size, color, and custom options</li><li><strong>Product Categories &amp; Tags</strong> — dedicated, first-class taxonomy</li><li><strong>Shopping cart</strong> — session-based, persistent</li><li><strong>Coupon codes</strong> — percentage or fixed discount</li><li><strong>Checkout</strong> — guest or registered customer</li><li><strong>Multiple payment gateways</strong> — PayPal, Stripe, SSLCommerz</li><li><strong>Order management</strong> — status workflow, invoices, refunds</li><li><strong>Product reviews</strong> with moderation</li><li><strong>Wishlist</strong></li><li><strong>Order tracking</strong> — customers track by order number + email</li></ul><h2 id="setup-checklist" tabindex="-1">Setup Checklist <a class="header-anchor" href="#setup-checklist" aria-label="Permalink to &quot;Setup Checklist&quot;">​</a></h2><ol><li><p><strong>Create pages</strong> — Falcon CMS auto-creates Shop, Cart, Checkout, and Account pages during <code>falcon:install</code>. If missing, create them and assign in settings.</p></li><li><p><strong>Configure Shop Settings</strong> — Go to <strong>Admin → Shop → Settings</strong>:</p><ul><li>Currency and format</li><li>Tax rate</li><li>Shipping method and rate</li><li>Payment gateways</li></ul></li><li><p><strong>Add Products</strong> — Admin → Products → Add New</p></li><li><p><strong>Test checkout</strong> — Add a product to cart and complete a test order</p></li></ol><h2 id="shop-settings" tabindex="-1">Shop Settings <a class="header-anchor" href="#shop-settings" aria-label="Permalink to &quot;Shop Settings&quot;">​</a></h2><p>Navigate to <strong>Admin → Shop → Settings</strong>:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Currency</td><td>USD, EUR, BDT, GBP, etc.</td></tr><tr><td>Currency position</td><td>Before or after price</td></tr><tr><td>Decimal places</td><td>Price formatting (e.g., 2 → <code>$10.00</code>)</td></tr><tr><td>Shop page</td><td>Post ID of your main shop/products page</td></tr><tr><td>Cart page</td><td>Post ID of cart page</td></tr><tr><td>Checkout page</td><td>Post ID of checkout page</td></tr><tr><td>Account page</td><td>Post ID of customer account page</td></tr><tr><td>Guest checkout</td><td>Allow checkout without an account</td></tr><tr><td>Shipping method</td><td><code>flat_rate</code>, <code>free</code>, or <code>calculated</code></td></tr><tr><td>Flat rate</td><td>Cost for flat rate shipping</td></tr><tr><td>Tax enabled</td><td>Enable/disable tax calculation</td></tr><tr><td>Tax rate</td><td>Percentage (e.g., <code>10</code> for 10%)</td></tr></tbody></table><h2 id="payment-gateways" tabindex="-1">Payment Gateways <a class="header-anchor" href="#payment-gateways" aria-label="Permalink to &quot;Payment Gateways&quot;">​</a></h2><h3 id="paypal" tabindex="-1">PayPal <a class="header-anchor" href="#paypal" aria-label="Permalink to &quot;PayPal&quot;">​</a></h3><ol><li>Go to <strong>Admin → Settings → Integrations</strong></li><li>Enable PayPal</li><li>Enter Client ID and Secret (from PayPal Developer Dashboard)</li><li>Select Sandbox / Live mode</li></ol><h3 id="stripe" tabindex="-1">Stripe <a class="header-anchor" href="#stripe" aria-label="Permalink to &quot;Stripe&quot;">​</a></h3><ol><li>Enable Stripe in Integrations settings</li><li>Enter Public Key and Secret Key (from Stripe Dashboard)</li></ol><h3 id="sslcommerz-south-asia" tabindex="-1">SSLCommerz (South Asia) <a class="header-anchor" href="#sslcommerz-south-asia" aria-label="Permalink to &quot;SSLCommerz (South Asia)&quot;">​</a></h3><ol><li>Enable SSLCommerz</li><li>Enter Store ID and Signature Key</li></ol><h2 id="shop-dashboard" tabindex="-1">Shop Dashboard <a class="header-anchor" href="#shop-dashboard" aria-label="Permalink to &quot;Shop Dashboard&quot;">​</a></h2><p><strong>Admin → Shop → Overview</strong> shows:</p><ul><li>Total Orders</li><li>Net Revenue (gross minus refunds)</li><li>Gross Revenue</li><li>Total Refunded</li><li>Average Order Value</li><li>Order status breakdown chart</li></ul><p>All stats are filterable by: Today, Last 7 days, Last 30 days, This month, This year, All time, Custom range.</p>',20)])])}const g=e(i,[["render",s]]);export{u as __pageData,g as default};
